  ('dietitian-moex-10474', 'dietitian', 'dietitian-moex-094-4665e2ba', 'sub-dietitian-01', NULL, 'single_choice', '非專業健康顧問（lay health advisor）模式或病患團體的支持與資訊提供都是下列何種營養教育理論的延伸？ 社會認知理論（Social cognitive theory）  社會支持（Social support） 健康信仰模式（Health belief model）  改變階段模式（Stages of change model）', '["", "", "", ""]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:56+00:00", "source_pdf_sha1": "1ecb2ba898bd", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "094020", "c": "112", "s": "5001", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "公共衛生營養學", "year": "094", "exam_name": "094年第一次專技醫事人員、中醫師、心理師、呼吸治療師、營養師、獸醫人員考試", "original_question_number": 28, "answer_corrected": false, "flags": ["answer_missing", "incomplete_options"], "slug": "dietitian", "db_exam_id": "dietitian"}'::jsonb, NULL),
  ('dietitian-moex-10475', 'dietitian', 'dietitian-moex-094-4665e2ba', 'sub-dietitian-01', NULL, 'single_choice', '根據食品衛生管理法之規定，管灌營養品屬於那一種食品？ 病人食品  特殊營養食品  健康食品  保健食品', '["", "", "", ""]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:56+00:00", "source_pdf_sha1": "1ecb2ba898bd", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "094020", "c": "112", "s": "5001", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "公共衛生營養學", "year": "094", "exam_name": "094年第一次專技醫事人員、中醫師、心理師、呼吸治療師、營養師、獸醫人員考試", "original_question_number": 29, "answer_corrected": false, "flags": ["answer_missing", "incomplete_options"], "slug": "dietitian", "db_exam_id": "dietitian"}'::jsonb, NULL),
  ('dietitian-moex-10476', 'dietitian', 'dietitian-moex-094-4665e2ba', 'sub-dietitian-01', NULL, 'single_choice', '根據營養師法規定，營養諮詢機構之申請人應具備下列何種資格？ 領有營養師證書者 曾在醫學中心執行營養師業務三年以上之營養師 曾在教學醫院執行營養師業務五年以上之營養師 曾在教學醫院或營養諮詢機構執行營養師業務三年以上之營養師', '["", "", "", ""]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:56+00:00", "source_pdf_sha1": "1ecb2ba898bd", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "094020", "c": "112", "s": "5001", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "公共衛生營養學", "year": "094", "exam_name": "094年第一次專技醫事人員、中醫師、心理師、呼吸治療師、營養師、獸醫人員考試", "original_question_number": 30, "answer_corrected": false, "flags": ["answer_missing", "incomplete_options"], "slug": "dietitian", "db_exam_id": "dietitian"}'::jsonb, NULL),
  ('dietitian-moex-10477', 'dietitian', 'dietitian-moex-094-4665e2ba', 'sub-dietitian-01', NULL, 'single_choice', '張小姐身高160公分，體重64公斤。請問根據衛生署的建議，她的體重應屬於下列那一個範圍？ 過輕  正常  過重  肥胖', '["", "", "", ""]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:56+00:00", "source_pdf_sha1": "1ecb2ba898bd", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "094020", "c": "112", "s": "5001", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "公共衛生營養學", "year": "094", "exam_name": "094年第一次專技醫事人員、中醫師、心理師、呼吸治療師、營養師、獸醫人員考試", "original_question_number": 31, "answer_corrected": false, "flags": ["answer_missing", "incomplete_options"], "slug": "dietitian", "db_exam_id": "dietitian"}'::jsonb, NULL),
  ('dietitian-moex-10478', 'dietitian', 'dietitian-moex-094-4665e2ba', 'sub-dietitian-01', NULL, 'single_choice', '負責我國學生午餐計畫之中央行政主管機關為： 教育部  行政院衛生署  內政部兒童福利局  行政院農業委員會', '["", "", "", ""]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:56+00:00", "source_pdf_sha1": "1ecb2ba898bd", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "094020", "c": "112", "s": "5001", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "公共衛生營養學", "year": "094", "exam_name": "094年第一次專技醫事人員、中醫師、心理師、呼吸治療師、營養師、獸醫人員考試", "original_question_number": 32, "answer_corrected": false, "flags": ["answer_missing", "incomplete_options"], "slug": "dietitian", "db_exam_id": "dietitian"}'::jsonb, NULL),
  ('dietitian-moex-10479', 'dietitian', 'dietitian-moex-094-4665e2ba', 'sub-dietitian-01', NULL, 'single_choice', '張小姐將自己的營養師證照租借給某安養機構使用，請問依據營養師法，她會受到何種處罰？ 處一個月以上一年以下停業處分  吊銷其營養師執業執照 廢止其營養師證書    處新台幣一萬元以上五萬元以下罰鍰', '["", "", "", ""]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:56+00:00", "source_pdf_sha1": "1ecb2ba898bd", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "094020", "c": "112", "s": "5001", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "公共衛生營養學", "year": "094", "exam_name": "094年第一次專技醫事人員、中醫師、心理師、呼吸治療師、營養師、獸醫人員考試", "original_question_number": 33, "answer_corrected": false, "flags": ["answer_missing", "incomplete_options"], "slug": "dietitian", "db_exam_id": "dietitian"}'::jsonb, NULL),
  ('dietitian-moex-10480', 'dietitian', 'dietitian-moex-094-4665e2ba', 'sub-dietitian-01', NULL, 'single_choice', '李小姐每天飲食中之烹調用油約為55公克，請問該攝取量與「每日飲食指南」之油脂建議量相較： 少2茶匙  少1茶匙  多1茶匙  多2茶匙', '["", "", "", ""]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:56+00:00", "source_pdf_sha1": "1ecb2ba898bd", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "094020", "c": "112", "s": "5001", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "公共衛生營養學", "year": "094", "exam_name": "094年第一次專技醫事人員、中醫師、心理師、呼吸治療師、營養師、獸醫人員考試", "original_question_number": 34, "answer_corrected": false, "flags": ["answer_missing", "incomplete_options"], "slug": "dietitian", "db_exam_id": "dietitian"}'::jsonb, NULL),
  ('dietitian-moex-10481', 'dietitian', 'dietitian-moex-094-4665e2ba', 'sub-dietitian-01', NULL, 'single_choice', '王教授設計了一份鈣質攝取量的飲食頻率問卷。經測試後發現，該問卷在評量個人每日鈣質攝取量時，均 會高估約 15%的攝取量。但若重複利用此問卷測量同一個人時，則前後兩次鈣質之攝取量又相當接近。請 問此種情形表示，此問卷之何種測量能力不佳？ 效度  信度  再現性  一致性', '["", "", "", ""]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:56+00:00", "source_pdf_sha1": "1ecb2ba898bd", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "094020", "c": "112", "s": "5001", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "公共衛生營養學", "year": "094", "exam_name": "094年第一次專技醫事人員、中醫師、心理師、呼吸治療師、營養師、獸醫人員考試", "original_question_number": 35, "answer_corrected": false, "flags": ["answer_missing", "incomplete_options"], "slug": "dietitian", "db_exam_id": "dietitian"}'::jsonb, NULL),
  ('dietitian-moex-10482', 'dietitian', 'dietitian-moex-094-4665e2ba', 'sub-dietitian-01', NULL, 'single_choice', '某位肥胖患者在營養諮詢時，表達其面對食物時無法控制食慾的感覺。營養師表示其能感受到相同的感受 ，此種現象稱為： 面質  同情心  同理心  分享', '["", "", "", ""]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:56+00:00", "source_pdf_sha1": "1ecb2ba898bd", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "094020", "c": "112", "s": "5001", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "公共衛生營養學", "year": "094", "exam_name": "094年第一次專技醫事人員、中醫師、心理師、呼吸治療師、營養師、獸醫人員考試", "original_question_number": 36, "answer_corrected": false, "flags": ["answer_missing", "incomplete_options"], "slug": "dietitian", "db_exam_id": "dietitian"}'::jsonb, NULL),
  ('dietitian-moex-10483', 'dietitian', 'dietitian-moex-094-4665e2ba', 'sub-dietitian-01', NULL, 'single_choice', '陳教授想探討臺灣地區居民飲食中何種因子與肝癌的發生有相關性存在，而擬就一項研究計畫。該計畫擬 募集10萬名沒有罹患肝癌之研究對象，在評量過所有研究對象之各項飲食因子後，陳教授每年追蹤一次各 研究對象之身體健康狀況，並予以紀錄。10 年後陳教授依此記錄分析飲食中何種因子與肝癌之發生有相關 性。請問此研究計畫屬於何種流行病學研究？ 世代研究  病例對照研究  臨床研究  社區實驗研究', '["", "", "", ""]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:56+00:00", "source_pdf_sha1": "1ecb2ba898bd", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "094020", "c": "112", "s": "5001", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "公共衛生營養學", "year": "094", "exam_name": "094年第一次專技醫事人員、中醫師、心理師、呼吸治療師、營養師、獸醫人員考試", "original_question_number": 37, "answer_corrected": false, "flags": ["answer_missing", "incomplete_options"], "slug": "dietitian", "db_exam_id": "dietitian"}'::jsonb, NULL)
